package com.oneil.wellness.walkplanner.activity;import static org.assertj.core.api.Assertions.*;import static org.mockito.Mockito.*;import com.oneil.wellness.walkplanner.history.*;import java.time.*;import java.util.*;import org.junit.jupiter.api.*;class OpportunityExpiryServiceTest{HistoryRepository history=mock(HistoryRepository.class);OpportunityOutcomeRepository outcomes=mock(OpportunityOutcomeRepository.class);WalkActivityRepository activities=mock(WalkActivityRepository.class);OpportunityExpiryService service=new OpportunityExpiryService(history,outcomes,activities);RecommendationHistory eligible(){OffsetDateTime start=OffsetDateTime.now(ZoneOffset.UTC).minusHours(2);return new RecommendationHistory(new RecommendationSnapshot(Instant.now().minusSeconds(7200),85,start,start.plusMinutes(30),70d,5d,40d,20d,2d,true,List.of("MANUAL"),"Available opportunity."));}@Test void expiresEligibleUnknownOpportunityOnce(){var value=eligible();when(history.findTop100ByRecommendedEndBeforeAndCalendarAvailableTrueAndScoreGreaterThanEqualOrderByRecommendedEndAsc(any(),eq(60))).thenReturn(List.of(value));when(outcomes.findByRecommendationHistoryId(value.getId())).thenReturn(Optional.empty());when(activities.findByOpportunityStartAndOpportunityEnd(value.getRecommendedStart(),value.getRecommendedEnd())).thenReturn(List.of());assertThat(service.classify()).isEqualTo(1);verify(outcomes).save(any(OpportunityOutcome.class));}@Test void excludesExistingOutcomeAndActiveSession(){RecommendationHistory existing=eligible();RecommendationHistory active=eligible();when(history.findTop100ByRecommendedEndBeforeAndCalendarAvailableTrueAndScoreGreaterThanEqualOrderByRecommendedEndAsc(any(),eq(60))).thenReturn(List.of(existing,active));when(outcomes.findByRecommendationHistoryId(existing.getId())).thenReturn(Optional.of(new OpportunityOutcome(existing.getId(),ActivityStatus.SKIPPED,ActivitySource.DASHBOARD)));when(outcomes.findByRecommendationHistoryId(active.getId())).thenReturn(Optional.empty());WalkActivity session=WalkActivity.start(new WalkRequest(null,active.getRecommendedStart(),active.getRecommendedEnd(),ActivitySource.DASHBOARD),Instant.now());when(activities.findByOpportunityStartAndOpportunityEnd(active.getRecommendedStart(),active.getRecommendedEnd())).thenReturn(List.of(session));assertThat(service.classify()).isZero();verify(outcomes,never()).save(any());}}
